import sys
class Solution:
    def solve(self, nums: list[int]) -> list[int]:
        result = list()
        i = 0
        while i < len(nums):
            if i == len(nums) - 1 or nums[i] != nums[i + 1]:
                result.append(nums[i])
                i += 1
        if len(result) == 0:
            result.append(-1)
        return result
if __name__ == '__main__':
    T = int(input())
    nums = list(map(int, input().split()))
    solution = Solution()
    result = solution.solve(nums)
    for num in result:
        sys.stdout.write(str(num) + ' ')
    sys.stdout.write('\n')

