#include <bits/stdc++.h>
using namespace std;

#define ll long long
#define ld long double
#define mod 1000000007
#define M 100000000

class Solution {
public:
	vector<int> solve(vector<int>& nums) {
		vector<int> result;
		for (int i = 1; i < nums.size(); i++) {
			if (nums[i] != nums[i-1]) {
				result.push_back(nums[i]);
			}
		}
		if (result.empty()) {
			result.push_back(-1);
		}
		return result;
	}
};

int main() {
	ios_base::sync_with_stdio(0); cin.tie(0);
	int T;
	cin >> T;
	vector<int> nums(T);
	for (int& num : nums) {
		cin >> num;
	}
	Solution solution;
	vector<int> result = solution.solve(nums);
	for (int num : result) {
		cout << num << ' ';
	}
	cout << '\n';
	return 0;
}
